const express = require('express');
const app = express();
const twilio = require('twilio');
const crypto = require('crypto');

app.use(express.json());

const client = twilio(process.env.TWILIO_ACCOUNT_SID, process.env.TWILIO_AUTH_TOKEN);
const codes = new Map();
const users = new Map();

const generateCode = () => {
  return Math.floor(100000 + Math.random() * 900000).toString();
};

const sendSMS = async (phoneNumber, code) => {
  try {
    await client.messages.create({
      body: `Your verification code is: ${code}`,
      from: process.env.TWILIO_PHONE_NUMBER,
      to: phoneNumber
    });
    return true;
  } catch (error) {
    console.error('SMS sending failed:', error);
    return false;
  }
};

const isValidPhoneNumber = (phone) => {
  const phoneRegex = /^\+?[1-9]\d{1,14}$/;
  return phoneRegex.test(phone);
};

const isCodeValid = (code, timestamp) => {
  const now = Date.now();
  const codeTime = parseInt(timestamp);
  return now - codeTime < 300000; // 5 minutes validity
};

app.post('/send-otp', async (req, res) => {
  const { phoneNumber } = req.body;
  
  if (!phoneNumber || !isValidPhoneNumber(phoneNumber)) {
    return res.status(400).json({ error: 'Invalid phone number' });
  }
  
  const code = generateCode();
  const timestamp = Date.now().toString();
  
  const success = await sendSMS(phoneNumber, code);
  
  if (!success) {
    return res.status(500).json({ error: 'Failed to send SMS' });
  }
  
  codes.set(phoneNumber, { code, timestamp });
  users.set(phoneNumber, { verified: false });
  
  res.json({ message: 'Verification code sent' });
});

app.post('/verify-otp', (req, res) => {
  const { phoneNumber, code } = req.body;
  
  if (!phoneNumber || !code) {
    return res.status(400).json({ error: 'Phone number and code required' });
  }
  
  const stored = codes.get(phoneNumber);
  
  if (!stored) {
    return res.status(400).json({ error: 'No code found for this number' });
  }
  
  if (!isCodeValid(stored.code, stored.timestamp)) {
    codes.delete(phoneNumber);
    return res.status(400).json({ error: 'Code expired' });
  }
  
  if (stored.code !== code) {
    return res.status(400).json({ error: 'Invalid code' });
  }
  
  codes.delete(phoneNumber);
  users.set(phoneNumber, { verified: true });
  
  res.json({ message: 'Verification successful' });
});

app.post('/login', (req, res) => {
  const { phoneNumber } = req.body;
  
  if (!phoneNumber) {
    return res.status(400).json({ error: 'Phone number required' });
  }
  
  const user = users.get(phoneNumber);
  
  if (!user || !user.verified) {
    return res.status(401).json({ error: 'Not verified' });
  }
  
  res.json({ message: 'Login successful' });
});

module.exports = app;